import { Component, Input, Output } from '@angular/core';

export interface User{
  name:string;
  age:number;
  city:string;
}

@Component({
  selector: 'app-child',
  templateUrl: './child.component.html',
  styleUrls: ['./child.component.scss']
})
export class ChildComponent {
  @Input() user!:User;


  @Output() childData: String = "This is child data";



}
